 85	func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
 86		history, err := s.History(metricID)
 87		if err != nil {
 88			return HistoryRecord{}, ComparisonResult{}, err
 89		}
 90		if len(history) == 0 {
 91			return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
 92		}
 93		if _, err := singleHistoryUnit(metricID, history); err != nil {
 94			return HistoryRecord{}, ComparisonResult{}, err
 95		}
 96		current := history[len(history)-1]
 97		target, err := selectComparisonTarget(history, against)
 98		if err != nil {
 99			return HistoryRecord{}, ComparisonResult{}, err
100		}
101		result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
102		current.Comparison = result
103		return current, result, nil
104	}
