259			enc := json.NewEncoder(cmd.OutOrStdout())
260			enc.SetIndent("", "  ")
261			return enc.Encode(summary)
262		}
263		fmt.Fprintf(cmd.OutOrStdout(), "%s  count=%d  avg=%.3f%s  min=%.3f  max=%.3f\n", summary.MetricID, summary.Count, summary.Average, summary.Unit, summary.Min, summary.Max)
264		return nil
265	}
266	
267	func joinCommand(parts []string) string {
268		if len(parts) == 0 {
269			return "(none)"
270		}
271		return strings.Join(parts, " ")
272	}
